mapper.delete:
DELETE FROM long_term_memories USING (
    SELECT id FROM long_term_memories WHERE user_id = #{userId} ORDER BY created_at ASC LIMIT #{count}
) AS sub WHERE long_term_memories.id = sub.id

mapper.select:
SELECT id, user_id, content, source_type, embedding, created_at
FROM long_term_memories WHERE user_id = #{userId} AND embedding IS NOT NULL
ORDER BY 1 - (embedding <=> #{queryVec}::vector) DESC LIMIT #{limit}
